// Discover candidate services via Railway GraphQL + diff vs registry + idle
const RAILWAY_TOKEN = '90daac78-15a0-441c-9f11-1f10ed4b92c4';
const N8N_KEY = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJzdWIiOiIwNzJlZjdlNy04ZWI4LTRiNmMtYTc2ZS05YWUxMTIwOGNkYjciLCJpc3MiOiJuOG4iLCJhdWQiOiJwdWJsaWMtYXBpIiwianRpIjoiMmE2NDEzZDgtNGZmNS00MDU1LThlNGEtZDdjZjUzODRmNmMxIiwiaWF0IjoxNzc3NDUyMDI4fQ.z_wAAqXb-jMfKXtqZx-pljq-aN6RxUW82gM1-n8V7-Y';
const BASE = 'https://n8n-production-986a.up.railway.app';
const REG = 'gZRuzAmWa9sNwGc6';
const IDLE = '0lrRutLikjTH1SPj';
const REALERT_HOURS = 24;

const query = `query { projects { edges { node { id name services { edges { node { id name deployments(first: 1) { edges { node { status staticUrl } } } serviceInstances { edges { node { domains { serviceDomains { domain } customDomains { domain } } } } } } } } } } } }`;

const rwl = await this.helpers.httpRequest({
  method: 'POST', url: 'https://backboard.railway.app/graphql/v2',
  headers: {'Authorization': 'Bearer ' + RAILWAY_TOKEN, 'Content-Type': 'application/json'},
  body: {query}, json: true, timeout: 15000
});

const [registry, idle] = await Promise.all([
  this.helpers.httpRequest({method: 'GET', url: BASE + '/api/v1/data-tables/' + REG + '/rows?limit=250', headers: {'X-N8N-API-KEY': N8N_KEY}, json: true, timeout: 10000}),
  this.helpers.httpRequest({method: 'GET', url: BASE + '/api/v1/data-tables/' + IDLE + '/rows?limit=250', headers: {'X-N8N-API-KEY': N8N_KEY}, json: true, timeout: 10000})
]);
const known = new Set((registry.data || []).map(r => r.name));
const recentlyIdle = new Set();
const now = Date.now();
for (const r of (idle.data || [])) {
  const last = r.last_attempt_at ? new Date(r.last_attempt_at).getTime() : 0;
  if (now - last < REALERT_HOURS * 3600 * 1000) recentlyIdle.add(r.service_name);
}

const infra = /^(postgres|redis|mysql|mongo|valkey|minio|sandbox|storage|database|worker|runner|chroma|weaviate|plugin|auto-setup|sandbox)/i;
const candidates = [];
for (const p of (rwl.data?.projects?.edges || [])) {
  for (const s of (p.node.services.edges || [])) {
    const svc = s.node;
    if (infra.test(svc.name)) continue;
    if (svc.deployments.edges[0]?.node?.status !== 'SUCCESS') continue;
    const domains = (svc.serviceInstances.edges || []).flatMap(e => [
      ...(e.node.domains?.serviceDomains || []).map(d => d.domain),
      ...(e.node.domains?.customDomains || []).map(d => d.domain)
    ]);
    if (domains.length === 0) continue;
    const candidateName = svc.name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
    if (known.has(candidateName)) continue;
    if (recentlyIdle.has(svc.name)) continue;
    candidates.push({
      candidate_name: candidateName,
      original_name: svc.name,
      project_id: p.node.id,
      project_name: p.node.name,
      service_id: svc.id,
      public_url: 'https://' + domains[0]
    });
  }
}

return candidates.length === 0 ? [{json: {empty: true}}] : candidates.map(c => ({json: c}));

// Decide: register / failed_validation / silent
const candidate = $('Discover candidates').item.json;
const probeRes = $input.first().json;
const statusCode = $input.first().json.statusCode || ($input.first().json && Object.keys($input.first().json).length > 0 ? 200 : 0);

// Check if probe succeeded and got JSON
let manifest = null;
let valid = false;
let errors = [];

if (probeRes && typeof probeRes === 'object' && probeRes.name) {
  manifest = probeRes;
  // Validate
  if (!manifest.name || !/^[a-z0-9-]+$/.test(manifest.name)) errors.push('name לא תקין');
  if (!manifest.public_url) manifest.public_url = candidate.public_url;
  if (!manifest.category) errors.push('category חסר');
  if (!Array.isArray(manifest.capabilities) || manifest.capabilities.length === 0) errors.push('capabilities ריק');
  if (!manifest.endpoints || typeof manifest.endpoints !== 'object') errors.push('endpoints חסר');
  valid = errors.length === 0;
}

let outcome;
if (valid) outcome = 'register';
else if (manifest) outcome = 'failed_validation';
else outcome = 'silent';

return [{json: {
  outcome, candidate, manifest, errors, errors_text: errors.join('\n• ')
}}];
